import { readdirSync, readFileSync, writeFileSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'
import prettier from 'prettier'

const packageRoot = join(dirname(fileURLToPath(import.meta.url)), '..')
const distDir = join(packageRoot, 'report-ui/dist')
const scriptBundle = readdirSync(distDir).find((file) => file.endsWith('.js'))
const styleBundle = readdirSync(distDir).find((file) => file.endsWith('.css'))

if (!scriptBundle) {
  throw new Error(`Could not find report UI script bundle in ${distDir}`)
}

if (!styleBundle) {
  throw new Error(`Could not find report UI style bundle in ${distDir}`)
}

const script = readFileSync(join(distDir, scriptBundle), 'utf8')
const style = readFileSync(join(distDir, styleBundle), 'utf8')
const outputFile = join(packageRoot, 'src/analyze-report.generated.ts')
const prettierOptions = (await prettier.resolveConfig(outputFile)) ?? {}
const generated = await prettier.format(
  `// Generated by packages/cli/scripts/write-analyze-report-bundle.mjs
// Do not edit directly.

export const analyzeReportScript = ${JSON.stringify(script)}
export const analyzeReportStyle = ${JSON.stringify(style)}
`,
  { ...prettierOptions, filepath: outputFile, parser: 'typescript' },
)

writeFileSync(outputFile, generated)
